8101e8c11636e1162c5a795254285e6c7b5de5a7:
fragment TrackFields on ManifestState {
  id
  owner
  schemaId
  schemaName
  manifestCid
  version
  lastUpdated
}

query GetTracks($first: Int!, $skip: Int!) {
  manifestStates(
    first: $first
    skip: $skip
    where: {schemaId: "0xe6ed6e175ef6277d28ef468c7c9b9be6c79d337e6c642d65a877b145fabd0d1a"}
  ) {
    ...TrackFields
    manifest {
      files {
        name
        fileFields {
          name
          value
          atType
          acc
          pricing {
            price
            currency
          }
        }
      }
    }
  }
}

query SearchTracks($search: String!) {
  manifestStates(
    where: {schemaId: "0xe6ed6e175ef6277d28ef468c7c9b9be6c79d337e6c642d65a877b145fabd0d1a"}
    first: 100
  ) {
    ...TrackFields
    manifest {
      files {
        name
        fileFields {
          name
          value
          atType
          acc
          pricing {
            price
            currency
          }
        }
      }
    }
  }
}

