    where: {owner: $owner, schemaId: "0xe6ed6e175ef6277d28ef468c7c9b9be6c79d337e6c642d65a877b145fabd0d1a"}
    first: $first
    skip: $skip
  ) {
    ...TrackFields
    manifest {
